import React, { useState, useEffect, useRef } from 'react'
import useData from './data';
import { useTableContext } from './Provider';
import { pageLimit } from './data';

function InfiniteScroll({children}) {
  const [page,setPage] = useState(0)
  const { loading, error, tableData, total } = useData(page);
  const [hasMore, setHasMore] = useState(false)
  const { setTableData } = useTableContext()
  const loaderRef = useRef(null)

  useEffect(() => {
    const observer = new IntersectionObserver((entries) => {
        if(entries[0].isIntersecting) {
        setPage(page => page + 1)
        }
    }, {
        threshold: 1
    })
    if(loaderRef.current) {
    observer.observe(loaderRef.current)
    }
    return () => {
        if(loaderRef.current) {
        observer.unobserve(loaderRef.current)
        }
    }
  },[hasMore])
  useEffect(() => {
   if(tableData) {
      console.log('skip,pageLimit>>>', page,pageLimit)
      setTableData(tableData)
      if(tableData.length < total) {
      setHasMore(hasMore => !hasMore)
      }
   }
  },[tableData])
  console.log('hasMore', hasMore)
    return (
        <>
        {children}
        {hasMore && <div ref={loaderRef}>...Loading</div>}
        </>
    )
}

export default InfiniteScroll
